typedef struct{float x,y,z;}V;typedef struct{V o,d;}R;typedef struct{float t;V p,n;int h;}H;
V v(float x,float y,float z){V a={x,y,z};return a;}V A(V a,V b){return v(a.x+b.x,a.y+b.y,a.z+b.z);}V S(V a,V b){return v(a.x-b.x,a.y-b.y,a.z-b.z);}V M(V a,float s){return v(a.x*s,a.y*s,a.z*s);}float D(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}V N(V a){float l=sqrt(D(a,a));return M(a,1/l);}R ray(V o,V d){R r={o,N(d)};return r;}V at(R r,float t){return A(r.o,M(r.d,t));}
H sph(R r,V c,float q){H h={0};V oc=S(r.o,c);float a=D(r.d,r.d),b=2*D(oc,r.d),g=D(oc,oc)-q*q,e=b*b-4*a*g;if(e<0)return h;float t=(-b-sqrt(e))/(2*a);if(t<.001)t=(-b+sqrt(e))/(2*a);if(t<.001)return h;h.t=t;h.p=at(r,t);h.n=N(S(h.p,c));h.h=1;return h;}
H pln(R r,float y){H h={0};if(fabs(r.d.y)<.0001)return h;float t=(y-r.o.y)/r.d.y;if(t<.001)return h;h.t=t;h.p=at(r,t);h.n=v(0,1,0);h.h=1;return h;}
V sky(R r){float t=.5*(r.d.y+1);return A(M(v(1,1,1),1-t),M(v(.5,.7,1),t));}
V tr(R r,V c,float q,V l){H s=sph(r,c,q),p=pln(r,-1.5),h={0};int sp=0;if(s.h&&(!p.h||s.t<p.t))h=s,sp=1;else if(p.h)h=p;else return sky(r);float d=fmax(D(h.n,l),0);if(sph(ray(A(h.p,M(h.n,.001)),l),c,q).h)d=0;d=.2+.8*d;if(sp)return M(v(1,.2,.2),d);int k=((int)(floor(h.p.x)+floor(h.p.z)))&1;return M(k?v(.4,.4,.4):v(.9,.9,.9),d);}
int C(float x){if(x<0)x=0;if(x>1)x=1;return x*255.99;}int main(){int W=2400,Hh=1800;FILE*f=fopen("reconstructed.ppm","w");fprintf(f,"P3\n%d %d\n255\n",W,Hh);V c=v(0,-.5,-5),l=N(v(1,1,-1));float vw=(float)W/Hh*2;for(int y=0;y<Hh;y++)for(int x=0;x<W;x++){float u=(float)x/(W-1),w=(float)y/(Hh-1);V d=v(-vw/2+u*vw,1-2*w,-1),r=tr(ray(v(0,0,0),d),c,1);fprintf(f,"%d %d %d\n",C(r.x),C(r.y),C(r.z));}fclose(f);}

